mapper.select:
SELECT * FROM ( SELECT IM.IMPORT_ID ID, IM.IMPORT_NUMBER DECL_NUMBER, IM.STATUS STATUS, IM.ITEM_NAME_DECLARED ITEM_NAME, TO_CHAR(IM.SUBMIT_DATE, 'YYYY-MM-DD') SUBMIT_DATE, TO_CHAR(NVL(IM.MOD_DATE, IM.SUBMIT_DATE), 'YYYY-MM-DD') STATUS_DATE, NVL(AD.DOC_COMMENT, '보완/정정 요청') DOC_COMMENT, 'IMPORT' TYPE FROM IMPORT_MASTER IM LEFT OUTER JOIN ( SELECT DOC_NUMBER, DOC_COMMENT, ROW_NUMBER() OVER(PARTITION BY DOC_NUMBER ORDER BY CHECK_DATE DESC) IDX FROM AI_DOC_CHECK ) AD ON IM.IMPORT_NUMBER = AD.DOC_NUMBER AND AD.IDX = 1 WHERE IM.STATUS = 'SUPPLEMENT'
AND IM.MEM_ID = #{memId}
ORDER BY NVL(IM.MOD_DATE, IM.SUBMIT_DATE) ASC ) WHERE ROWNUM <= #{limit}

SELECT * FROM ( SELECT EM.EXPORT_ID ID, EM.EXPORT_NUMBER DECL_NUMBER, EM.STATUS STATUS, EM.ITEM_NAME_DECLARED ITEM_NAME, TO_CHAR(EM.SUBMIT_DATE, 'YYYY-MM-DD') SUBMIT_DATE, TO_CHAR(NVL(EM.REG_DATE, EM.SUBMIT_DATE), 'YYYY-MM-DD') STATUS_DATE, '보완/정정 요청' DOC_COMMENT, 'EXPORT' TYPE FROM EXPORT_MASTER EM WHERE EM.STATUS = 'SUPPLEMENT'
AND EM.MEM_ID = #{memId}
ORDER BY NVL(EM.REG_DATE, EM.SUBMIT_DATE) ASC ) WHERE ROWNUM <= #{limit}

SELECT * FROM ( SELECT IM.IMPORT_ID ID, IM.IMPORT_NUMBER DECL_NUMBER, IM.STATUS STATUS, IM.ITEM_NAME_DECLARED ITEM_NAME, TO_CHAR(IM.SUBMIT_DATE, 'YYYY-MM-DD') SUBMIT_DATE, TO_CHAR(NVL(IM.MOD_DATE, IM.SUBMIT_DATE), 'YYYY-MM-DD') STATUS_DATE, NVL(AD.DOC_COMMENT, '반려 처리') DOC_COMMENT, 'IMPORT' TYPE FROM IMPORT_MASTER IM LEFT OUTER JOIN ( SELECT DOC_NUMBER, DOC_COMMENT, ROW_NUMBER() OVER(PARTITION BY DOC_NUMBER ORDER BY CHECK_DATE DESC) IDX FROM AI_DOC_CHECK ) AD ON IM.IMPORT_NUMBER = AD.DOC_NUMBER AND AD.IDX = 1 WHERE IM.STATUS = 'REJECTED'
AND IM.MEM_ID = #{memId}
ORDER BY NVL(IM.MOD_DATE, IM.SUBMIT_DATE) DESC ) WHERE ROWNUM <= #{limit}

SELECT * FROM ( SELECT EM.EXPORT_ID ID, EM.EXPORT_NUMBER DECL_NUMBER, EM.STATUS STATUS, EM.ITEM_NAME_DECLARED ITEM_NAME, TO_CHAR(EM.SUBMIT_DATE, 'YYYY-MM-DD') SUBMIT_DATE, TO_CHAR(NVL(EM.REG_DATE, EM.SUBMIT_DATE), 'YYYY-MM-DD') STATUS_DATE, '반려 처리' DOC_COMMENT, 'EXPORT' TYPE FROM EXPORT_MASTER EM WHERE EM.STATUS = 'REJECTED'
AND EM.MEM_ID = #{memId}
ORDER BY NVL(EM.REG_DATE, EM.SUBMIT_DATE) DESC ) WHERE ROWNUM <= #{limit}

SELECT COUNT(*)
FROM IMPORT_MASTER



            STATUS IN ('WAITING', 'REVIEWING')


            STATUS = 'PAY_COMPLETED'


            STATUS = #{status}


    AND MEM_ID = #{memId}

SELECT COUNT(*)
FROM EXPORT_MASTER



            STATUS IN ('WAITING', 'REVIEWING')


            STATUS = #{status}


    AND MEM_ID = #{memId}

SELECT CAL.MON MONTH, NVL(D.REJECT_CNT, 0) REJECT_COUNT, NVL(D.SUPPLEMENT_CNT, 0) SUPPLEMENT_COUNT FROM ( SELECT TO_CHAR(ADD_MONTHS(SYSDATE, -LEVEL + 1), 'YYYY-MM') MON FROM DUAL CONNECT BY LEVEL <= 6 ) CAL LEFT OUTER JOIN ( SELECT MON, SUM(R_CNT) REJECT_CNT, SUM(S_CNT) SUPPLEMENT_CNT FROM ( SELECT TO_CHAR(NVL(IM.MOD_DATE, IM.SUBMIT_DATE), 'YYYY-MM') MON, CASE WHEN IM.STATUS = 'REJECTED' THEN 1 ELSE 0 END R_CNT, CASE WHEN IM.STATUS = 'SUPPLEMENT' THEN 1 ELSE 0 END S_CNT FROM IMPORT_MASTER IM WHERE NVL(IM.MOD_DATE, IM.SUBMIT_DATE) >= ADD_MONTHS(TRUNC(SYSDATE, 'MM'), -5) AND IM.STATUS IN ('REJECTED', 'SUPPLEMENT') AND IM.MEM_ID = #{memId}
UNION ALL
SELECT TO_CHAR(NVL(EM.REG_DATE, EM.SUBMIT_DATE), 'YYYY-MM') MON, CASE WHEN EM.STATUS = 'REJECTED' THEN 1 ELSE 0 END R_CNT, CASE WHEN EM.STATUS = 'SUPPLEMENT' THEN 1 ELSE 0 END S_CNT FROM EXPORT_MASTER EM WHERE NVL(EM.REG_DATE, EM.SUBMIT_DATE) >= ADD_MONTHS(TRUNC(SYSDATE, 'MM'), -5) AND EM.STATUS IN ('REJECTED', 'SUPPLEMENT') AND EM.MEM_ID = #{memId} ) GROUP BY MON ) D ON CAL.MON = D.MON ORDER BY CAL.MON ASC

SELECT COUNT(*) FROM IMPORT_MASTER
WHERE MEM_ID = #{memId}
  AND STATUS = #{status}
  AND TRUNC(NVL(MOD_DATE, SUBMIT_DATE)) = TRUNC(SYSDATE)

SELECT COUNT(*) FROM EXPORT_MASTER
WHERE MEM_ID = #{memId}
  AND STATUS = #{status}
  AND TRUNC(NVL(REG_DATE, SUBMIT_DATE)) = TRUNC(SYSDATE)

SELECT COUNT(*) FROM IMPORT_MASTER
WHERE MEM_ID = #{memId}
  AND STATUS NOT IN ('APPROVED', 'DELIVERED')

SELECT COUNT(*) FROM EXPORT_MASTER
WHERE MEM_ID = #{memId}
  AND STATUS NOT IN ('APPROVED', 'DELIVERED')

SELECT COUNT(*) FROM IMPORT_MASTER
WHERE TRUNC(NVL(MOD_DATE, SUBMIT_DATE), 'YYYY') = TRUNC(SYSDATE, 'YYYY')
AND MEM_ID = #{memId}

SELECT COUNT(*) FROM EXPORT_MASTER
WHERE TRUNC(NVL(REG_DATE, SUBMIT_DATE), 'YYYY') = TRUNC(SYSDATE, 'YYYY')
AND MEM_ID = #{memId}
